import 'package:flutter/material.dart';import '../tokens/piyi_colors.dart';import '../tokens/piyi_radius.dart';
class PiyiPrimaryButton extends StatelessWidget{const PiyiPrimaryButton({super.key,required this.label,required this.onPressed,this.icon,this.isLoading=false});final String label;final VoidCallback? onPressed;final IconData? icon;final bool isLoading;@override Widget build(BuildContext context){return FilledButton(onPressed:isLoading?null:onPressed,child:isLoading?const SizedBox(width:22,height:22,child:CircularProgressIndicator(strokeWidth:2,color:Colors.white)):Row(mainAxisSize:MainAxisSize.min,children:[if(icon!=null)...[Icon(icon),const SizedBox(width:8)],Text(label)]));}}
class PiyiSecondaryButton extends StatelessWidget{const PiyiSecondaryButton({super.key,required this.label,required this.onPressed,this.icon});final String label;final VoidCallback? onPressed;final IconData? icon;@override Widget build(BuildContext context)=>OutlinedButton.icon(onPressed:onPressed,icon:Icon(icon??Icons.arrow_forward),label:Text(label),style:OutlinedButton.styleFrom(minimumSize:const Size.fromHeight(52),shape:RoundedRectangleBorder(borderRadius:BorderRadius.circular(PiyiRadius.lg))));}
class PiyiDangerButton extends StatelessWidget{const PiyiDangerButton({super.key,required this.label,required this.onPressed,this.icon});final String label;final VoidCallback? onPressed;final IconData? icon;@override Widget build(BuildContext context)=>FilledButton.icon(onPressed:onPressed,icon:Icon(icon??Icons.warning),label:Text(label),style:FilledButton.styleFrom(backgroundColor:PiyiColors.error,foregroundColor:Colors.white,minimumSize:const Size.fromHeight(52),shape:RoundedRectangleBorder(borderRadius:BorderRadius.circular(PiyiRadius.lg))));}
